onClick:
{{
  (function() {
    const total = Number(inp_carriage_cost.text || 0);
    if (total <= 0) {
      showAlert('Enter a carriage cost greater than 0', 'warning');
      return;
    }
    qry_distribute_carriage.run(
      function() {
        const perAsset = (total / (qry_asset_summary_total.data[0]?.total_booked || 1)).toFixed(2);
        showAlert('Carriage cost distributed: £' + perAsset + ' per asset', 'success');
        qry_asset_breakdown_by_type.run();
      },
      function(error) {
        showAlert('Failed to distribute carriage cost — ' + error.message, 'error');
      }
    );
  })()
}}
